// We pakken de tekst die de Chat Agent wil versturen
let aiResponse = $input.item.json.output;

// We definiëren verboden woorden (ALLEEN de interne codes)
const verbodenWoorden = ["STATUS:", "SAMENVATTING:", "KLANT:", "ADRES:"];

// Check of de tekst een verboden woord bevat
const bevatVerbodenWoord = verbodenWoorden.some(woord => aiResponse.includes(woord));

// Scenario 1: De AI is in de war en stuurt een Status-update naar de klant
if (bevatVerbodenWoord) {
  return {
    json: {
      safe_output: "Bedankt! Ik zorg dat Jansen dit ontvangt."
    }
  };
}

// Scenario 2: De AI doet normaal
return {
  json: {
    safe_output: aiResponse
  }
};

